<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/><title>Admin – TronSick</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap" rel="stylesheet"/><link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css"/><link rel="stylesheet" href="admin.css"/></head><body><div class="adm-wrap"><aside class="adm-sb"><div class="sb-logo"><i class="fas fa-shield-halved" style="color:#3ecf8e;font-size:20px"></i><span class="sb-logo-txt">Tron<span>Sick</span></span><span class="sb-logo-badge">ADMIN</span></div><div class="sb-section">Main</div><button class="sb-item active" onclick="showSection(this,'dashboard')"><i class="fas fa-chart-line"></i><span>Dashboard</span></button><button class="sb-item" onclick="showSection(this,'users')"><i class="fas fa-users"></i><span>Users</span></button><div class="sb-section">Site Features</div><button class="sb-item" onclick="showSection(this,'faucet')"><i class="fas fa-faucet"></i><span>Faucet</span></button><button class="sb-item" onclick="showSection(this,'bonus')"><i class="fas fa-dice"></i><span>Bonus</span></button><button class="sb-item" onclick="showSection(this,'games')"><i class="fas fa-gamepad"></i><span>Games</span></button><button class="sb-item" onclick="showSection(this,'contest')"><i class="fas fa-trophy"></i><span>Contest</span></button><button class="sb-item" onclick="showSection(this,'cashback')"><i class="fas fa-money-bill-trend-up"></i><span>Cashback</span></button><button class="sb-item" onclick="showSection(this,'gifts')"><i class="fas fa-gift"></i><span>Gift Codes</span></button><button class="sb-item" onclick="showSection(this,'affiliate')"><i class="fas fa-handshake"></i><span>Affiliate</span></button><div class="sb-section">Finance</div><button class="sb-item" onclick="showSection(this,'withdraw')"><i class="fas fa-money-bill-transfer"></i><span>Withdrawals</span></button><button class="sb-item" onclick="showSection(this,'deposit')"><i class="fas fa-wallet"></i><span>Deposits</span></button><button class="sb-item" onclick="showSection(this,'payment')"><i class="fas fa-credit-card"></i><span>OxaPay Gateway</span></button><div class="sb-section">System</div><button class="sb-item" onclick="showSection(this,'contact')"><i class="fas fa-envelope"></i><span>Contact Msgs</span></button><button class="sb-item" onclick="showSection(this,'settings')"><i class="fas fa-gear"></i><span>Settings</span></button><div class="sb-section">Tools</div><button class="sb-item" onclick="showSection(this,'payout_gen')"><i class="fas fa-money-bill-wave"></i><span>Payout Generate</span></button><button class="sb-item" onclick="showSection(this,'contest_gen')"><i class="fas fa-trophy"></i><span>Contest Generate</span></button><button class="sb-item" onclick="showSection(this,'fake_check')"><i class="fas fa-robot"></i><span>Fake Acc Checker</span></button><div class="sb-gap"></div><div class="sb-bottom"><button class="sb-logout" onclick="doLogout()"><i class="fas fa-right-from-bracket"></i><span>Logout</span></button></div></aside><div class="adm-main"><header class="adm-topbar"><div class="tb-title" id="tbTitle">Dashboard Overview</div><div class="tb-right"><span class="tb-badge"><i class="fas fa-circle" style="font-size:7px"></i> LIVE</span><span class="tb-user"><i class="fas fa-user-shield"></i> Admin</span><span class="tb-time" id="tbTime"></span></div></header><div class="adm-content" id="admContent"></div></div></div><script src="admin.js"></script></body></html>
